# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, id, balance=0):
        self.id = id
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            return False

    def withdrawal(self, amount):
        if amount <= self.balance:
            self.balance -= amount
            return True
        else:
            return False

class TransactionProcessor:
    def __init__(self):
        self.accounts = {}

    def open_account(self, id):
        if id not in self.accounts:
            self.accounts[id] = Account(id)
            return True
        else:
            return False

    def close_account(self, id):
        if id in self.accounts:
            del self.accounts[id]
            return True
        else:
            return False

    def process_transaction(self, id, transaction_type, amount):
        if id not in self.accounts or transaction_type not in ['deposit', 'withdrawal'] or amount <= 0:
            return False
        
        account = self.accounts[id]
        if transaction_type == 'deposit':
            account.deposit(amount)
        else:
            account.withdrawal(amount)
        
        return True

    def get_balance(self, id):
        if id in self.accounts:
            return self.accounts[id].balance
        else:
            return None